import{_ as n,o as t,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const i="/images/lekt5101.jpg",o="/images/lekt5103.jpg",l="/images/lekt5102.jpg",s="/images/lekt5104.jpg",u="/images/lekt5105.jpg",p="/images/lekt5106.jpg",m="/images/lekt5107.jpg",c="/images/lekt5108.jpg",h="/images/lekt5109.jpg",d="/images/lekt5110.jpg",b="/images/lekt5111.jpg",k="/images/lekt5112.jpg",g="/images/lekt5113.jpg",f="/images/lekt5114.jpg",q="/images/lekt5115.jpg",w="/images/lekt5116.jpg",z="/images/lekt5118.jpg",v="/images/lekt5117.jpg",y=JSON.parse('{"title":"Lektion 51","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion51.md","filePath":"lektionen/lektion51.md"}'),_={name:"lektionen/lektion51.md"};function A(N,e,S,B,P,j){return t(),r("div",null,[...e[0]||(e[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-51" tabindex="-1">Lektion 51 <a class="header-anchor" href="#lektion-51" aria-label="Permalink to &quot;Lektion 51&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>51.1. उपपद-Komposita</li><li>51.2. Deklination der Stämme, die auf einen einfachen Konsonanten (außer Nasal, Halbvokal, -s) auslauten <ul><li>51.2.1. Stämme auf nichtpalatalen Verschlusslaut</li><li>51.2.2. Stämme auf palatalen Verschlusslaut (c, ch, j), ś, ṣ</li><li>51.2.3. Stämme auf -h</li></ul></li><li>51.3. Sandhi von anlautendem h-</li><li>51.4. Sandhi von anlautendem ch-</li><li>51.5. -ch- im Wortinnern</li><li>51.6. Wortliste</li><li>51.7. Übersetzungsübung</li></ul><h2 id="_51-1-उपपद-komposita" tabindex="-1">51.1. उपपद-Komposita <a class="header-anchor" href="#_51-1-उपपद-komposita" aria-label="Permalink to &quot;51.1. उपपद-Komposita&quot;">​</a></h2><p>उपपद-Komposita (उपपद n. &quot;Begleitwort&quot;) sind तत्पुरुष mit einem Verbalnomen als Hinterglied, das nur als Hinterglied von Komposita auftritt, nicht aber als selbständiges, einzelnes Wort. उपपद werden mit den कृत्-Suffixen</p><ul><li>-Ø</li><li>-a</li><li>-t</li></ul><p>gebildet. Sie sind Nomina agentis, d. h. sie bezeichnen einen Agens (कर्तृ), der die durch die zugrundeliegende Wurzel bezeichnete Handlung tut.</p><p>Solche Komposita werden von den einheimischen Kommentatoren nicht durch Nominalkombinationen, sondern mittels Verbalformen aufgelöst:</p><p>Beispiele:</p><blockquote><p>सुखकरः = सुखं करोतीति सुखकरः</p><p>कुलघ्नः =  कुलम्हन्तीति कुलघ्नः</p></blockquote><p>Beispiele:</p><p>a) कृत्-Suffix -Ø</p><blockquote><p>-नी 3 &quot;führend&quot; z.B. सेनानी m. &quot;Heerführer&quot; (सेना f. &quot;Heer&quot;)</p><p>-भुज् 3 &quot;genießend, essen&quot; z.B. भूमिभुज् m. &quot;König&quot; (भूमि f. &quot;Erde&quot;)</p><p>-विद् 3 &quot;wissend&quot; z.B. धर्मविद्  3 &quot;den Dharma kennend&quot;</p></blockquote><p><img src="'+i+'" alt=""><br> Abb.: भूमिभुज्<br> ज्ञानेन्द्र वीर बिक्रम शाह, नेपालस्यान्तिमो राजा (2001 - 2008)<br> [Bildquelle: kanjiroushi. -- <a href="http://www.flickr.com/photos/kanjiroushi/321594765/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/kanjiroushi/321594765/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><p>b) कृत्-Suffix -t</p><blockquote><p>-कृत् 3 &quot;machend&quot; z. B.</p><blockquote><p>कुलक्षयकृत् 3 &quot;Vernichtung der Familie bewirkend&quot;</p><p>पापकृत् 3 &quot;Böses tuend, Übeltäter&quot;</p></blockquote><p>-जित् 3 &quot;besiegend&quot;, z. B.</p><blockquote><p>शत्रुजित् 3 &quot;die Feinde besiegend&quot;</p><p>पुरुजित् 3 &quot;viele besiegend&quot; (पुरु 3 &quot;viel, reichlich&quot;)</p></blockquote><p>-भृत् 3 &quot;tragend&quot; z. B.  भूमिभृत् m. &quot;König&quot;</p></blockquote><p><img src="'+o+'" alt=""><br> Abb.: पापकृत्<br> भरतपुर, राजस्थान<br> [Bildquelle: jeffmcneill. -- <a href="http://www.flickr.com/photos/jeffmcneill/83251043/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/jeffmcneill/83251043/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><p>c) कृत्-Suffix -a</p><blockquote><p>-ग 3 &quot;gehend (in, zu)&quot; (vermutlich zur Wurzel gā, Tiefst. g + a) z.B. खग 3 &quot;fliegend&quot; m. &quot;Vogel, Wandelstern&quot; (ख n. &quot;Loch, &#39;Luft&#39;raum&quot;)</p><p>-घ्न 3 &quot;erschlagend&quot; z.B. कुलघ 3 &quot;Familie(n) tötend&quot;</p><p>-ज 3 (jña » jā » Tiefst. j + a) &quot;abstammend von, geboren in&quot; z.B. आत्मज &quot;Sohn&quot;</p><p>-ज्ञ 3 &quot;kundig&quot; (jñ-a) z.B. सर्वज्ञ 3 &quot;allwissend&quot;</p><p>-द 3 &quot;gebend&quot; (d-a) z.B. वारिद m. &quot;Wolke&quot; (वारि n. &quot;Wasser&quot;)</p><p>-प 3 &quot;trinkend&quot; (p-a) z.B. द्विप m. &quot;Elefant (zweimal trinkend)&quot;</p><p>-प 3 &quot;schützend&quot; (p-a) z.B. भूप &quot;die Erde schützend = König&quot;</p><p>-स्थ 3 &quot;stehend in, befindlich in&quot; (sth-a) z.B. गृहस्थ m. &quot;Haushalter, Hausvater&quot;</p><p>-कर 3 &quot;bewirkend, tuend&quot; z.B. सुखकर 3 &quot;Glück verschaffend&quot;</p><p>-स्मर 3 &quot;sich erinnernd&quot; z.B. जातिस्मर 3 &quot;sich früherer Geburten erinnernd&quot;</p></blockquote><p><img src="'+l+'" alt=""><br> Abb.: द्विपो द्विर्पिबति : हस्तेन च मुखेन च<br> नेपाल<br> [Bildquelle: amanderson2. -- <a href="http://www.flickr.com/photos/amanderson/2420198291/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/amanderson/2420198291/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung)]</p><h2 id="_51-2-deklination-der-stamme-die-auf-einen-einfachen-konsonanten-außer-nasal-halbvokal-s-auslauten" tabindex="-1">51.2. Deklination der Stämme, die auf einen einfachen Konsonanten (außer Nasal, Halbvokal, -s) auslauten <a class="header-anchor" href="#_51-2-deklination-der-stamme-die-auf-einen-einfachen-konsonanten-außer-nasal-halbvokal-s-auslauten" aria-label="Permalink to &quot;51.2. Deklination der Stämme, die auf einen einfachen Konsonanten (außer Nasal, Halbvokal, -s) auslauten&quot;">​</a></h2><p>Stämme, die auf einen einfachen Konsonanten (außer Nasal, Halbvokal, -s) auslauten, haben keine Stammabstufung. Die Deklination geschieht völlig regelmäßig durch Anfügung der regulären Kasusendungen.</p><p>Einzige Unregelmäßigkeit: im Nom.,Akk.,Vok.pl.Neutrum wird vor den Stammauslaut ein Nasal eingeschoben.</p><h3 id="_51-2-1-stamme-auf-nichtpalatalen-verschlusslaut" tabindex="-1">51.2.1. Stämme auf nichtpalatalen Verschlusslaut <a class="header-anchor" href="#_51-2-1-stamme-auf-nichtpalatalen-verschlusslaut" aria-label="Permalink to &quot;51.2.1. Stämme auf nichtpalatalen Verschlusslaut&quot;">​</a></h3><p>Es gelten die üblichen Lautveränderungsgesetze, d.h.</p><ul><li>im Auslaut steht der entsprechende stimmlose Nichtaspirat</li><li>vor dem -su des Lok.plur wird der Auslaut zunächst durch den entsprechenden stimmlosen Nichtaspiraten ersetzt, dann treten die entsprechenden Lautveränderungen ein</li><li>vor stimmhaftem Konsonanten wird der Auslaut durch den entsprechenden stimmhaften Nichtaspiraten ersetzt.</li></ul><p>Beispiele:</p><p>शत्रुजित् 3 &quot;Feinde besiegend&quot;</p><blockquote><p>Maskulinum, Femininum:</p><blockquote><p>Singular:</p><blockquote><p>Nom.Vok. शत्रुजित् (śatrujit + s)<br> Akk. शत्रुजितम्</p></blockquote><p>Plural:</p><blockquote><p>Nom.Akk.Vok. शत्रुजितस्<br> Instr. शत्रुजिद्भिस्<br> Lok. शत्रुजित्सु</p></blockquote></blockquote><p>Neutrum</p><blockquote><p>Singular Nom.Akk.Vok.  शत्रुजित्<br> Plural Nom.Akk.Vok. शत्रुजिन्ति</p></blockquote></blockquote><p>सुयुध् 3 &quot;gut kämpfend&quot;</p><blockquote><p>Singular.Nom.Vok.m.f.n. सुयुत्<br> u.s.w.</p></blockquote><p>Vollständige Paradigmen bei Kielhorn, Grammatik S. 16ff.</p><h3 id="_51-2-2-stamme-auf-palatalen-verschlusslaut-c-ch-j-s-s" tabindex="-1">51.2.2. Stämme auf palatalen Verschlusslaut (c, ch, j), ś, ṣ <a class="header-anchor" href="#_51-2-2-stamme-auf-palatalen-verschlusslaut-c-ch-j-s-s" aria-label="Permalink to &quot;51.2.2. Stämme auf palatalen Verschlusslaut (c, ch, j), ś, ṣ&quot;">​</a></h3><p>Vor vokalisch anlautender Endung bleibt der Auslaut des Stammes unverändert.</p><p>Vor den übrigen Endungen gilt:</p><ul><li>auslautendes -c und -j werden durch k ersetzt und der Stamm wird dann so behandelt, als ob er auf -k auslautete</li><li>in einigen Wörtern (Liste bei Kielhorn, Grammatik S. 18) wird auslautendes -j durch -ṭ ersetzt</li><li>auslautendes -ch wird durch -ṭ ersetzt</li><li>auslautendes -ś und -ṣ werden - mit einigen Ausnahmen - durch -ṭ ersetzt. In den Ausnahmefällen werden -ś und -ṣ durch -k ersetzt</li></ul><p>d. h.</p><ul><li>-c  » -k</li><li>-ch » -ṭ</li><li>-j » -k oder -ṭ</li><li>-ś » -ṭ oder -k</li><li>-ṣ » -ṭ oder -k</li></ul><p>Beispiele:</p><p>सत्यवाच् 3 &quot;die Wahrheit redend&quot; (बहुव्रीहि)</p><blockquote><p>Maskulinum, Femininum:</p><blockquote><p>Singular:</p><blockquote><p>Nom.Vok. सत्यवाक्<br> Akk. सत्यवाचम्<br> Instr. सत्यवाचा</p></blockquote><p>Plural:</p><blockquote><p>Instr. सत्यवाग्भिस्<br> Lok. सत्यवाक्षु</p></blockquote></blockquote><p>Neutrum</p><blockquote><p>Singular Nom.Akk.Vok. सत्यवाक् <br> Plural Nom.Akk.Vok. सत्यवाञ्चि</p></blockquote></blockquote><p>शेषभुज् 3 &quot;Speisereste essend&quot;</p><blockquote><p>Maskulinum, Femininum:</p><blockquote><p>Singular:</p><blockquote><p>Nom.Vok. शेषभुक्<br> Akk. शेषभुजम्</p></blockquote><p>Plural:</p><blockquote><p>Instr. शेषभुग्भिस्<br> Lok. शेषभुक्षु</p></blockquote></blockquote><p>Neutrum</p><blockquote><p>Singular Nom.Akk.Vok. शेषभुक् <br> Plural Nom.Akk.Vok. शेषभुञ्जि</p></blockquote></blockquote><p>परिव्राज् m. &quot;Wandermönch&quot;</p><blockquote><p>Maskulinum, Femininum:</p><blockquote><p>Singular:</p><blockquote><p>Nom.Vok. परिव्राट्<br> Akk. परिव्राजम्</p></blockquote><p>Plural:</p><blockquote><p>Instr. परिव्राड्भिस्<br> Lok. परिव्राट्सु</p></blockquote></blockquote></blockquote><p><img src="'+s+'" alt=""><br> Abb.: परिव्राट्<br> पुष्कर<br> [Bildquelle: calamur. -- <a href="http://www.flickr.com/photos/gargi/360186369/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/gargi/360186369/</a>. -- Zugriff am2009-01-13. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h3 id="_51-2-3-stamme-auf-h" tabindex="-1">51.2.3. Stämme auf -h <a class="header-anchor" href="#_51-2-3-stamme-auf-h" aria-label="Permalink to &quot;51.2.3. Stämme auf -h&quot;">​</a></h3><p>Vor vokalisch anlautender Endung bleibt das -h unverändert.</p><p>Vor den übrigen Endungen</p><ul><li>wird normalerweise das -h durch -ḍh ersetzt</li><li>lautet die zugrundeliegende Wurzel mit d- an, wird -h durch -gh ersetzt. Ebenso bei einigen anderen Wörtern wahlweise oder obligatorisch (Zusammenstellung bei Kielhorn, Grammatik §80,2)</li><li>(im Auslaut des Wurzelnomens wird -h durch -dh ersetzt)</li></ul><p>Nach diesen Ersetzungen wird der Stamm weiter behandelt, als ob  er auf -ḍh, -gh bzw. -dh auslauten würde.</p><p>Siehe die Paradigmen bei Kielhorn, Grammatik, S. 20f.</p><p>Beispiele:</p><blockquote><p>गुह् 3 &quot;verbergend&quot;</p><blockquote><p>Maskulinum, Femininum:</p><blockquote><p>Singular:</p><blockquote><p>Nom.Vok. घुट् (Grassmannsches Hauchdissimilationsgesetz: गुढ् + s)<br> Akk. गुहम्</p></blockquote><p>Plural:</p><blockquote><p>Instr. घुड्भिस्<br> Lok. घुट्सु</p></blockquote></blockquote></blockquote><p>द्रुह् &quot;schädigend, hassend&quot; (wahlweise -ḍh/-gh)</p><blockquote><p>Maskulinum, Femininum:</p><blockquote><p>Singular:</p><blockquote><p>Nom.Vok. ध्रुट् । ध्रुक्<br> Akk. द्रुहम्</p></blockquote><p>Plural:</p><blockquote><p>Instr. ध्रुड्भिस् । ध्रुग्भिस्<br> Lok. ध्रुट्सु । ध्रुक्षु</p></blockquote></blockquote></blockquote></blockquote><h2 id="_51-3-sandhi-von-anlautendem-h" tabindex="-1">51.3. Sandhi von anlautendem h- <a class="header-anchor" href="#_51-3-sandhi-von-anlautendem-h" aria-label="Permalink to &quot;51.3. Sandhi von anlautendem h-&quot;">​</a></h2><p>Vor anlautendem h- wird ein vorausgehender Verschlusslaut durch den entsprechenden stimmhaften Nichtaspiraten ersetzt und das anlautende h- durch den diesem Verschlusslaut entsprechenden stimmhaften Aspiraten:</p><blockquote><p>तत् + हि » तद्धि</p><p>वाक् + हि » वाग्घि</p><p>परिव्राट् + हि » परिव्राड्ढि</p></blockquote><h2 id="_51-4-sandhi-von-anlautendem-ch" tabindex="-1">51.4. Sandhi von anlautendem ch- <a class="header-anchor" href="#_51-4-sandhi-von-anlautendem-ch" aria-label="Permalink to &quot;51.4. Sandhi von anlautendem ch-&quot;">​</a></h2><p>Anlautendes ch- wird nach kurzem Vokal, nach मा &quot;nicht&quot; und nach आ &quot;zu&quot; durch cch- ersetzt:</p><blockquote><p>न + छिन्दति » न च्छिन्दति</p></blockquote><h2 id="_51-5-ch-im-wortinnern" tabindex="-1">51.5. -ch- im Wortinnern <a class="header-anchor" href="#_51-5-ch-im-wortinnern" aria-label="Permalink to &quot;51.5. -ch- im Wortinnern&quot;">​</a></h2><p>Im Wortinnern wird -ch- nach allen Vokalen durch -cch- ersetzt:</p><blockquote><p>z.B. छिद् » चिच्छेद</p></blockquote><h2 id="_51-6-wortliste" tabindex="-1">51.6. Wortliste <a class="header-anchor" href="#_51-6-wortliste" aria-label="Permalink to &quot;51.6. Wortliste&quot;">​</a></h2><p>अजिन n.: Antilopenfell, bes. das Fell der schwarzen Antilope (Hirschziegenantilope : <em>Antilope cervicapra</em> L. ). Kam ursprünglich auf dem ganzen indischen Subkontinent vor von Punjab und Sind bis Bengalen und von Nepal bis Kanyakumari (Cape Comorin) (Tamil: கன்னியாகுமரி) Siehe:</p><blockquote><p><strong>Walker&#39;s mammals of the world</strong> / Ronald M. Nowak. -- 6. ed. -- Baltimore [u.a.] : Johns Hopkins Univ. Pr., 1999. -- 2 Bde. -- ISBN 0-8018-5789-9. -- Bd. 2. -- S. 1193f.</p></blockquote><p><img src="'+u+'" alt=""><br> Abb.: Hirschziegenantilope -- <em>Antilope cervicapra</em> L., Bock<br> [Bildquelle: Wikipedia, public domain]</p><p>अतिथि m.: Gast</p><p>अभ्यन्तर 3: im Inneren befindlich, nächster ; m. der nächste Angehörige, Eingeborener</p><p>अरण्य n.: Wildnis, Wald</p><p>ऋतु m.: periodischer Vorgang, Jahreszeit, Zeitabschnitt, Menstruation, Zeit, in der die Frau empfängnisbereit ist und ein Anrecht auf Beischlaf ihres Gatten hat.</p><blockquote><p>Zu ऋतु siehe Manu III, 45-48: danach dauert ऋतु 16 Tage (nach der alternativen Übersetzung: 20 Tage) ab Beginn der Monatsblutung, an den ersten vier Tagen nach Beginn der Blutung ist Geschlechtsverkehr verboten (Nach der alternativen Übersetzung: an den ersten acht (4 + 4) Tagen), ebenso am 11. (bzw. 15.) und 13. (bzw. 18.) Tag. An geraden Tagen empfängt die Frau Söhne, an ungeraden Töchter. Für das Folgende wird ein ऋतु von insgesamt 16 Tagen (nicht die Alternativübersetzung) angenommen, wie es auch die meisten einheimischen Kommentare tun, und was also die vorherrschende Auffassung gewesen ist.</p><p>Da der Eisprung 14 Tage vor dem Beginn der Monatsblutung liegt, ist bei dieser Bestimmung der fruchtbaren Periode Fruchtbarkeit beinahe &quot;garantiert&quot; für einen Abstand der Monatsblutungen von 19 bis 30 Tagen. Die verbotenen Tage (11. und 13.) verbessern die Wahrscheinlichkeit für Geschlechtsverkehr am 12. und 14. Tag, d.h. die Empfängniswahrscheinlichkeit bei einem Zyklus von 28. Tagen (die Lebensdauer der Spermien in der Frau beträgt ca. 3 Tage). Diese Bestimmungen sind als sozusagen positiver Einsatz von Knaus-Ogino.</p></blockquote><p><img src="'+p+'" alt=""></p><blockquote><p>Abb.: &quot;Graphische Darstellung für die Berechnung der fruchtbaren Tage nach OGINO bei 26- bis 30tägigen Zyklusintervallen; gelbe Kästchen: maximale Lebensdauer der Spermien; blaue Kästchen: »Ovulationstermin«; a) 26tägiges Zyklusintervall: fruchtbare Tage vom 8. bis 15. Zyklustag; b) 30tägiges Zyklusintervall: fruchtbare Tage vom 12. bis 19. Zyklustag. Der untenstehende Pfeil #(pfb) gibt die fruchtbaren Tage für Zyklusintervalle von 26 bis 30 Tagen an = 8. bis 19. Zyklustag&quot; [Quelle für Text und Bild: Roche Lexikon Medizin. --  4.Auflage. -- München :  Urban &amp; Fischer Verlag, ©1984. -- Online: <a href="http://www.gesundheit.de/roche/ro20000/r20172.html" target="_blank" rel="noreferrer">http://www.gesundheit.de/roche/ro20000/r20172.html</a>. -- Zugriff am 2003-12-16]</p></blockquote><p>एकत्र Adv.: an einer Stelle</p><p>जटा f.: Haarflechte (Haartracht des Asketen)</p><p><img src="'+m+'" alt=""><br> Abb.: जटा<br> ऋषिकेश<br> [Bildquelle: EyalNow. -- <a href="http://www.flickr.com/photos/eyalnow/351734123/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/eyalnow/351734123/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>तुल्य 3: gleich, vergleichbar (तृतीयया)</p><p>तरय 3 (f.: तरयी): dreifältig, aus drei Teilen bestehend</p><p>प्राणान्तिक 3 (f.: -ī): tödlich, todbringend, lebenslänglich</p><p>बाह्य 3: außerhalb, draußen befindlich, fremd</p><p>भिक्षा f.: erbetteltes Almosen, Bettelspeise</p><p>मार्यादा f.: Grenze</p><p>शिष् 7P शिनष्टि : verlassen, übriglassen</p><blockquote><p>Perf.II शिशेषे, शिशिषुर्<br> Fut. शेक्ष्यति<br> Pass. शिष्यते<br> Kaus. शेषयति<br> PPPशिष्ट<br> Absol. -शिष्य</p></blockquote><p>शिष् + वि 7P विशिनष्टि : unterscheiden</p><blockquote><p>Pass. विशिष्यते : sich unterscheiden von (पञ्चम्या, तृतीयया), besser sein als (पञ्चम्या, तृतीयया), der beste sein unter (षष्ठ्या, सप्तम्या)</p></blockquote><p>समान 3: gleichartig, gleich, ähnlich ; m.: Altersgenosse</p><p>स्व 3: eigen, sein (mein, dein etc.) Wird wie सर्व dekliniert. Im Abl.Lok.sg.m.n und im Nom.pl.m kann es auch wie देव dekliniert werden:</p><blockquote><p>Abl.sg.m.n स्वस्मात् । स्वात्<br> Lok.sg.m.n. स्वस्मिन् । स्वे<br> Nom.pl.m स्वे । स्वास्</p></blockquote><p>गर्ह् 1Ā गर्हते 10P गर्हयति : schelten, tadeln</p><blockquote><p>Perf I जगर्हे<br> Fut. गर्हिष्यते<br> PPP गर्हित</p></blockquote><p>पिशित n.: (zubereitetes) Fleisch</p><p><img src="'+c+'" alt=""><br> Abb.: पिशितम्<br> Kolkata = কলকাতা <br> [Bildquelle: nicolas - نِيقُولاَوُسَ. --  <a href="http://www.flickr.com/photos/keep-on-moving/2994878670/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/keep-on-moving/2994878670/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>उपहार m.: Darbringung, Opfer, Geschenk</p><p>मधु n.: Honig, Süßtrank, Met (Honigwein)</p><p><img src="'+h+'" alt=""><br> Abb.: मधु<br> City Palace, उदयपुर<br> [Bildquelle: abrinsky. -- <a href="http://www.flickr.com/photos/abrinsky/457940260/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/abrinsky/457940260/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>मांस n.: Fleisch</p><p>मृगया f.: Jagd</p><p><img src="'+d+'" alt=""><br> Abb.: मृगया<br> Jagd mit चीता (<em>Acinonyx jubatus venaticus</em>) Gujarat = ગુજરાત, 1812<br> [Bildquelle: Wikipedia. Public domain]</p><p>शिवा f.: (weibl.) Schakal (Goldschakal = <em>Canis aureus</em>)</p><p><img src="'+b+'" alt=""><br> Abb.: शिवा (Weibchen?)<br><em>Canis aureus</em>, Kalatop Khajjiar Sanctuary<br> [Bildquelle: gautamnguitar. -- <a href="http://www.flickr.com/photos/gautamnguitar/2181211040/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/gautamnguitar/2181211040/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>रुत n.: Geschrei</p><p>कौशिक m.: Eule</p><p><img src="'+k+'" alt=""><br> Abb.: कौशिकः<br> Brahma-Kauz (<em>Athene brama</em>), Mahesana = મહેસાણા<br> [Bildquelle: Umang Dutt. -- <a href="http://www.flickr.com/photos/snapflickr/2790757825/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/snapflickr/2790757825/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>शकुनि m.: Vogel</p><p>श्वन् m.: Hund</p><blockquote><p>starker Stamm श्वान्<br> schwacher Stamm vor Vokal सुन्<br> schwacher Stamm vor Konsonant श्व</p></blockquote><p><img src="'+g+'" alt=""><br> Abb.: श्वा लिङ्गं च<br> Karnataka = ಕರ್ನಾಟಕ<br> [Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/150316450/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/150316450/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>परिचित 3: vertraut, bekannt</p><p>अटवी f.: Wald</p><p>शून्य 3: leer, öde</p><p>आपान(क) n.: Zechgelage</p><p><img src="'+f+'" alt=""><br> Abb.: आपानकम्<br> जोधपुर</p><blockquote><p>&quot;These men were sitting and drinking in front of sanctuary of some hindu god (I forgot the name). As they told me they were butchers and it was god of their profession who accepted sacrifices of alcohol only.&quot;</p><p>[Quelle von Bild und Text: zz77. -- <a href="http://www.flickr.com/photos/zz77/2255585927/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/zz77/2255585927/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p></blockquote><p>क्रूर 3: roh, grausam</p><p>दिह् 2U देग्धि, दिग्धे : bestreichen, beschmieren</p><blockquote><p>Perf. II दिदेह<br> Fut. धेक्ष्यति<br> Pass. दिह्यते<br> Kaus. देहयति<br> PPP दिग्ध</p></blockquote><p>विष n.: Gift</p><p><img src="'+q+'" alt=""><br> Abb.: मूषिकाविषाणि (मूषिका f. Maus, Ratte)<br> Bangalore = ಬೆಂಗಳೂರು<br> [Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/387955362/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/387955362/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>भुजंग m.: Schlange</p><p><img src="'+w+'" alt=""><br> Abb.: भुजंगः<br> Kettenviper (<em>Daboia russelii</em>), Bangalore = ಬೆಂಗಳೂರು<br> [Bildquelle: teemus. -- <a href="http://www.flickr.com/photos/teemus/455664680/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/teemus/455664680/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>सायक m.: Pfeil</p><p>उत्साद m.: Zugrundegehen</p><p>कलत्र Neutrum: Ehefrau, Weibchen</p><p>बन्दी f.: Gefangene, Raub</p><p>योषित् f.: junge Frau, Mädchen</p><p>शार्दूल m. = व्याघ्र m.</p><p>रुधिर n.: Blut</p><p>अर्चन n.  अर्चना f. = पूजा f.</p><p>बलि m.:  Abgabe, Spende, Tribut</p><p>मणि m.: Juwel</p><p><img src="'+z+'" alt=""><br> Abb.: मणिः<br> Hope Diamond aus Guntur = గుంటూరు, heute Smithsonian Museum of Natural History, Washington DC<br> [Bildquelle: David Bjorgen / Wikipedia. GNU FDLicense]</p><p>वन n.: Wald</p><p>मद m.: auch &quot;Brunstsaft&quot; eines Elefanten (im <a href="http://en.wikipedia.org/wiki/Musth" target="_blank" rel="noreferrer">Musht</a>)</p><p><img src="'+v+'" alt=""><br> Abb.: मदः<br> [Bildquelle: muzina_shanghai. -- <a href="http://www.flickr.com/photos/muzina_shanghai/2408592293/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/muzina_shanghai/2408592293/</a>. -- Zugriff am 2009-01-13. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>राग m.: auch: Farbe, rote Farbe</p><p>कालन n.: Wald</p><p>खन् 1U खनति : graben</p><blockquote><p>Perf. चखान, चखने<br> Fut. खनिष्यति<br> Kaus. खानयति<br> PPP खात<br> Absol खनित्वा । खात्वा</p></blockquote><p>चिन्त् 10 चिन्तयति : denken, nachdenken</p><p>शबर .:  Eigenname eines nichtarischen Stammes</p><h2 id="_51-7-ubersetzungsubung" tabindex="-1">51.7. Übersetzungsübung <a class="header-anchor" href="#_51-7-ubersetzungsubung" aria-label="Permalink to &quot;51.7. Übersetzungsübung&quot;">​</a></h2><p>१. कौटिलीयार्थशास्त्र १, ३, ९ - १२ आश्रमधर्मः</p><p>गृहस्तस्य स्वधर्माजीवस्तुल्यैरसमानार्षिभिर्वैवाह्यमृतुगामित्वं देवपित्रातिथिपूजा भृत्येषु त्यागः शेषभोजनं च ।९।<br> ब्रह्मचारिणः स्वाध्यायो ऽग्निकार्याभिषेकौ भैक्षाव्रतित्वमाचार्ये प्राणान्तिकी वृत्तिस्तदभावे गुरुपुत्रे सब्रह्मचारिणि वा ।१०।<br> वानप्रस्थस्य ब्रह्मचर्यं भूमौ शय्या जाटाजिनधारणमग्निहोत्राभिषेकौ देवतापित्रतिथिपूजा वन्यश्चाहारः ।११।<br> प्रव्राजकस्य जितेन्द्रियत्वमनारम्भो निष्किंचनत्वं सङ्गत्यागो भैक्षाव्रतमनेकत्रारण्ये च वासो बाह्याभ्यन्तरं च शौचम् ॥१२॥</p><p>Erklärung: -अभिषेकौ Nom.Akk.Vok.Dual.mask. (Dualdvandva)</p><p>२. कौटिलीयार्थशास्त्र १, ३, १६ - १७ Über die Notwendigkeit des Achtens auf den वर्नाश्रमधर्म</p><blockquote><p>तस्मात्स्वधर्मं भूतानाम्<br> राजा न व्यभिचारयेत् ।स्<br> स्वधर्मं संदधानो हि<br> प्रेत्य चेह च नन्दति ॥१६॥<br> व्यवस्थितार्यमर्यादः<br> कृतवर्णाश्रमस्थितिः ।<br> त्रय्याभिरक्षितो लोकः<br> प्रसीदति न सीदति ॥१७॥</p></blockquote><p>३. बाण (7. Jhdt. n. Chr.): कादम्बरी ed. K.P. Parab, 1896, S. 65ff.: Überlegungen des Papagei वैशम्पायन über das Jägerdasein:</p><p>आसीच्च मे मनसि -- अहो मोहप्रायमेतेषां जीवितं साधुजनगर्हितं च चरितम् । तथा हि । पुरुषपिशितोपहारे धर्मबुद्धिः , अहारः साधुजनगर्हितो मधुमांसादिः , श्रमो मृगया , शास्त्रं शिवारुतम् , समुपदेष्टारः सद्सतां कौशिकाः , प्रज्ञा शकुनिज्ञानम् , परिचिताः श्वानः , राज्यं शून्यास्वटवीषु , आपानकमुत्सवः , मित्राणि क्रुरकर्मसाधनानि धनूंषि , सहाया विषदिग्धमुखा भुजंगा इव सायकाः , गीतमुत्सादकारि मुग्धमृगाणाम् , कलत्राणि बन्दीगृहीताः परयोषितः , क्रूरात्मभिः शार्दूलैः सह संवासः , पशुरुधिरेण देवतार्चनम् , मांसेन बलिकर्म , चौर्येण जीवनम् , भूषणानि भुजंगमणयः , वनकरिमदैरङ्गरागः , यस्मिन्नेव कानने निवसन्ति तदेवोत्ख्यातमूलमशेषतः कुर्वत इति चिन्तयत्येव मयि शबरसेनापतिः समुपाविशत् ॥</p><p>४. Kommentar des भानुचन्द्र (16. Jhdt.) zu vorhergehendem Abschnit der कादम्बरी (diese Übung sollte unter Anleitung eines Lehrers übersetzt werden. Ist ein solcher nicht verfügbar, kann man sie übergehen)</p><p>आसीच्चेति । मे मम मनसि चित्त आसीद्बभूव । खेद इति शेषः । तदेव दर्शयति -- अहो इत्यादिना । अहो इत्याश्चर्ये । एतेषां भिल्लानां जीवितं प्राणितं मोहो ऽज्ञानं प्रायं प्रचुरं यत्र तादृशम् । चः पुनरर्थे । चरितमाचरणं साधुजनैः सज्जनजनैर्गर्हितं निन्दितम् । तदेव विशेषतो दर्शयति -- तथा हीति । पुरुषेति । पुरुषस्य पुंसो यत्पिशितं मांसं तस्य य उपहारो भगवत्यै नैवेद्यदर्शनं तस्मिन्धर्मबुद्धिः श्रेयोधीः । आहार इति । आहारः प्रत्यवसानं साधुजनैर्गर्हितो निन्दितो मधुमांसादिर्मधुः मद्यं माक्षिकं वा । मांसं प्रतीतम् । ते आदौ यस्येति बहुव्रीहिः । आदिशब्दात्कन्दादिपरिग्रहः । श्रम इति । श्रमः शक्तिसाधनायासो मृगयाखेटकः । शास्त्रमिति । शिवा सृगाली तस्य रुतं शब्दितं शास्त्रमुच्चस्वरवेदपाठः । प्रबोधजनकत्वसाम्यात्तदुपमानम् । सदिति । सदसतां शुभाशुभानां समुपदेष्टारो बोधकाः कौशिका उलूकाः । प्रज्ञेति । शकुनयः पत्त्रिणस्तेषां स्थूलमहत्त्वादिना ज्ञानं तदेव प्रज्ञा विवेकबुद्धिः । परीति । श्वानः सारमेयाः परिचिता विश्वासपालत्राणि । राज्यमिति । शून्यासु जनरहितासु विन्ध्याटवीषु राज्यं स्वामित्वम् । आपानकेति । उत्सवः संतुष्टिकार्यं तदेवापानमेवापानकम् । स्वार्थे कः । पानगोष्ठिका । मित्राणीति । क्रूरं यत्कर्म तत्साधनानि तद्धेतुभूतानि धनूंष्येव चापान्येव मित्राणि सहृदः । हितचिन्तकानीति यावत् । सहाया इति । विषेण दिग्धं मुखमाननं येषामेवंविधाः सायका बाणास्त एव सहाया इष्टकार्यकर्तृत्वात्साहाय्यकारिणः । क इव । भुजंगाः सर्पा इव । एतेषां विषदिग्धमुखत्वं स्वाभाविकम् । तेषामौपाधिकमिति भावः । गीतमिति । मुग्धा अनभिज्ञा ये मृगा हरिणास्तेषामुत्साहकारि स्तब्धताविधायि गीतं गानम् । कलत्रेति । परयोषितो ऽन्यस्त्रिय एव बन्दी ग्रहकस्तद्रूपत्वेन गृहीताः स्त्रीकृताः कलत्राणि स्वपत्न्यः । क्रूरेति । क्रूरात्मभिर्दुष्टात्मभिः शार्दुलैश्चित्रकैः समं संवासः सहावस्थानम् । पश्वेति । पशवो महिषास्तेषां रुधिरेण रक्तेन देवतार्चनं देवपूजनम् । मांसेनेति । मांसेन पिशितेन बलिर्हन्तकरस्तत्कर्म तत्कृत्यम् । चौर्येणेति । चौर्येण परद्रव्यापहारेण जीवनं प्राणधारणम् । भूषणनीति । भूषणान्याभरणानि भुजंगमणयः सर्परत्नानि । पर्वतवासित्वात्तेषां ते सुलभा इति भावः । वनेति । वनकरिणामरण्यहस्तिनां मदैर्दानवारिभिरङ्गरागो विलेपनम् । यस्मिन्निति । अनिर्दिष्टनामनि कानने वने निवसन्ति निवासं कुर्वन्ति तदेव काननमशेषतः समग्रत उत्खातमुत्पाटितं मूलं मध्यभागो यस्यैवंभूतं कुर्वते विदधत इति पूर्वोक्तप्रकारेण मयि चन्तयति ध्यायति सत्येव ... ॥</p>',153)])])}const C=n(_,[["render",A]]);export{y as __pageData,C as default};
